import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import './AdminPage.css';

const API_URL = 'http://localhost:5001/api';

function AdminPage() {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [stats, setStats] = useState({});
  const [users, setUsers] = useState([]);
  const [properties, setProperties] = useState([]);
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const { token } = useAuth();

  useEffect(() => {
    fetchData();
  }, [activeTab]);

  const fetchData = async () => {
    setLoading(true);
    const config = { headers: { Authorization: `Bearer ${token}` } };
    
    try {
      if (activeTab === 'dashboard') {
        const statsRes = await axios.get(`${API_URL}/admin/stats`, config);
        setStats(statsRes.data);
      } else if (activeTab === 'users') {
        const usersRes = await axios.get(`${API_URL}/admin/users`, config);
        setUsers(usersRes.data);
      } else if (activeTab === 'properties') {
        const propsRes = await axios.get(`${API_URL}/admin/properties`, config);
        setProperties(propsRes.data);
      } else if (activeTab === 'messages') {
        const messagesRes = await axios.get(`${API_URL}/admin/messages`, config);
        setMessages(messagesRes.data);
      }
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = async (id) => {
    try {
      await axios.put(`${API_URL}/admin/properties/${id}/approve`, {}, {
        headers: { Authorization: `Bearer ${token}` }
      });
      fetchData();
    } catch (error) {
      console.error('Error approving property:', error);
    }
  };

  const handleReject = async (id) => {
    const reason = prompt('Укажите причину отклонения:');
    if (reason) {
      try {
        await axios.put(`${API_URL}/admin/properties/${id}/reject`, { reason }, {
          headers: { Authorization: `Bearer ${token}` }
        });
        fetchData();
      } catch (error) {
        console.error('Error rejecting property:', error);
      }
    }
  };

  const handleBlockUser = async (id, isBlocked) => {
    try {
      await axios.put(`${API_URL}/admin/users/${id}/block`, { is_blocked: !isBlocked }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      fetchData();
    } catch (error) {
      console.error('Error blocking user:', error);
    }
  };

  const handleDeleteProperty = async (id) => {
    if (window.confirm('Вы уверены, что хотите удалить это объявление?')) {
      try {
        await axios.delete(`${API_URL}/admin/properties/${id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        fetchData();
      } catch (error) {
        console.error('Error deleting property:', error);
      }
    }
  };

  const handleDeleteMessage = async (id) => {
    if (window.confirm('Вы уверены, что хотите удалить это сообщение?')) {
      try {
        await axios.delete(`${API_URL}/admin/messages/${id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        fetchData();
      } catch (error) {
        console.error('Error deleting message:', error);
      }
    }
  };

  const handleMarkAsRead = async (id) => {
    try {
      await axios.put(`${API_URL}/admin/messages/${id}/read`, {}, {
        headers: { Authorization: `Bearer ${token}` }
      });
      fetchData();
    } catch (error) {
      console.error('Error marking message:', error);
    }
  };

  return (
    <div className="admin-page">
      <h1>Панель администратора</h1>
      
      <div className="admin-tabs">
        <button className={activeTab === 'dashboard' ? 'active' : ''} onClick={() => setActiveTab('dashboard')}>
          Дашборд
        </button>
        <button className={activeTab === 'users' ? 'active' : ''} onClick={() => setActiveTab('users')}>
          Пользователи
        </button>
        <button className={activeTab === 'properties' ? 'active' : ''} onClick={() => setActiveTab('properties')}>
          Модерация
        </button>
        <button className={activeTab === 'messages' ? 'active' : ''} onClick={() => setActiveTab('messages')}>
          Сообщения {stats.newMessages > 0 && `(${stats.newMessages})`}
        </button>
      </div>

      {loading ? (
        <div className="loading">Загрузка...</div>
      ) : (
        <>
          {activeTab === 'dashboard' && (
            <div className="dashboard-stats">
              <div className="stat-card">
                <h3>Пользователи</h3>
                <p className="stat-number">{stats.users || 0}</p>
              </div>
              <div className="stat-card">
                <h3>Объявления</h3>
                <p className="stat-number">{stats.properties || 0}</p>
              </div>
              <div className="stat-card">
                <h3>На модерации</h3>
                <p className="stat-number">{stats.pending || 0}</p>
              </div>
              <div className="stat-card">
                <h3>Новые сообщения</h3>
                <p className="stat-number">{stats.newMessages || 0}</p>
              </div>
            </div>
          )}

          {activeTab === 'users' && (
            <div className="users-table-container">
              <table className="admin-table">
                <thead>
                  <tr>
                    <th>ID</th>
                    <th>Имя</th>
                    <th>Email</th>
                    <th>Телефон</th>
                    <th>Роль</th>
                    <th>Статус</th>
                    <th>Действия</th>
                  </tr>
                </thead>
                <tbody>
                  {users.map(user => (
                    <tr key={user.id}>
                      <td>{user.id}</td>
                      <td>{user.username}</td>
                      <td>{user.email}</td>
                      <td>{user.phone || '-'}</td>
                      <td>{user.role}</td>
                      <td>{user.is_blocked ? 'Заблокирован' : 'Активен'}</td>
                      <td>
                        {user.role !== 'admin' && (
                          <button 
                            className={user.is_blocked ? 'unblock-btn' : 'block-btn'}
                            onClick={() => handleBlockUser(user.id, user.is_blocked)}
                          >
                            {user.is_blocked ? 'Разблокировать' : 'Заблокировать'}
                          </button>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {activeTab === 'properties' && (
            <div className="properties-table-container">
              <table className="admin-table">
                <thead>
                  <tr>
                    <th>ID</th>
                    <th>Название</th>
                    <th>Цена</th>
                    <th>Владелец</th>
                    <th>Статус</th>
                    <th>Действия</th>
                  </tr>
                </thead>
                <tbody>
                  {properties.map(property => (
                    <tr key={property.id}>
                      <td>{property.id}</td>
                      <td>{property.title}</td>
                      <td>{Number(property.price).toLocaleString()} ₽</td>
                      <td>{property.owner_name}</td>
                      <td>
                        <span className={`status-badge status-${property.status}`}>
                          {property.status === 'pending' ? 'На модерации' : 
                           property.status === 'active' ? 'Активно' : 'Отклонено'}
                        </span>
                      </td>
                      <td>
                        {property.status === 'pending' && (
                          <>
                            <button className="approve-btn" onClick={() => handleApprove(property.id)}>
                              Одобрить
                            </button>
                            <button className="reject-btn" onClick={() => handleReject(property.id)}>
                              Отклонить
                            </button>
                          </>
                        )}
                        <button className="delete-btn" onClick={() => handleDeleteProperty(property.id)}>
                          Удалить
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {activeTab === 'messages' && (
            <div className="messages-container">
              {messages.length === 0 ? (
                <div className="no-messages">Нет сообщений от пользователей</div>
              ) : (
                <div className="messages-list">
                  {messages.map(message => (
                    <div key={message.id} className={`message-card ${message.status === 'new' ? 'unread' : ''}`}>
                      <div className="message-header">
                        <div className="message-sender">
                          <strong>{message.name}</strong>
                          <span className="message-email">{message.email}</span>
                          {message.phone && <span className="message-phone">📞 {message.phone}</span>}
                        </div>
                        <div className="message-date">
                          {new Date(message.created_at).toLocaleString('ru-RU')}
                          {message.status === 'new' && <span className="new-badge">Новое</span>}
                        </div>
                      </div>
                      <div className="message-body">
                        {message.message}
                      </div>
                      <div className="message-actions">
                        {message.status === 'new' && (
                          <button onClick={() => handleMarkAsRead(message.id)} className="mark-read-btn">
                            Отметить прочитанным
                          </button>
                        )}
                        <button onClick={() => handleDeleteMessage(message.id)} className="delete-message-btn">
                          Удалить
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}
        </>
      )}
    </div>
  );
}

export default AdminPage;
